     1→//! View types and navigation for the FORGE TUI.
     2→//!
     3→//! Views represent the different screens/modes available in the dashboard.
     4→
     5→use std::fmt;
     6→
     7→/// Available views in the FORGE dashboard.
     8→///
     9→/// Each view represents a distinct screen with its own content and interactions.
    10→/// Views can be switched using hotkeys or the Tab key to cycle.
    11→#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
    12→pub enum View {
    13→    /// Overview/dashboard showing summary of all components
    14→    #[default]
    15→    Overview,
    16→    /// Worker pool management and status
    17→    Workers,
    18→    /// Task queue and bead management
    19→    Tasks,
    20→    /// Cost analytics and optimization
    21→    Costs,
    22→    /// Performance metrics and statistics
    23→    Metrics,
    24→    /// FORGE internal performance (event loop, render time, memory)
    25→    Perf,
    26→    /// Activity log viewer
    27→    Logs,
    28→    /// Subscription tracking and utilization
    29→    Subscriptions,
    30→    /// Worker health alerts and notifications
    31→    Alerts,
    32→    /// Conversational chat interface (activated with `:`)
    33→    Chat,
    34→}
    35→
    36→impl View {
    37→    /// Returns the hotkey character for this view.
    38→    pub fn hotkey(&self) -> char {
    39→        match self {
    40→            View::Overview => 'o',
    41→            View::Workers => 'w',
    42→            View::Tasks => 't',
    43→            View::Costs => 'c',
    44→            View::Metrics => 'm',
    45→            View::Perf => 'p',
    46→            View::Logs => 'l',
