    /// Success Criteria: Final state is correctly reflected, no intermediate stale data
    #[test]
    fn test_realtime_no_stale_data_after_rapid_changes() {
        let temp_dir = TempDir::new().unwrap();
        let status_dir = temp_dir.path().join("status");
