        std::thread::sleep(Duration::from_millis(100));
        while watcher.recv_timeout(Duration::from_millis(50)).is_some() {}

        // Simulate external termination: status file updated to 'stopped'
        let stopped_content = json!({
            "worker_id": worker_id,
            "status": "stopped",
            "current_task": null,
            "tasks_completed": 0
        });
