        assert!(LayoutMode::Narrow.meets_requirements(100, 25));
        assert!(!LayoutMode::Narrow.meets_requirements(80, 19)); // Height too short
        assert!(!LayoutMode::Narrow.meets_requirements(120, 20)); // Width triggers Wide
