        let mut file = fs::File::create(&log_path).unwrap();
        writeln!(file, r#"{{"type":"system","message":"init"}}"#).unwrap();

        // Poll should detect the new file
        let events = watcher.poll();
        assert_eq!(watcher.tracked_file_count(), 1);

