        // Format from parser tests: total_cost_usd at top level, usage has token counts
        let result_line = r#"{"type":"result","total_cost_usd":0.01,"usage":{"input_tokens":100,"output_tokens":50}}"#;
        writeln!(file, "{}", result_line).unwrap();

