        assert_eq!(metrics.total_input_tokens, 1000);
        assert_eq!(metrics.total_output_tokens, 500);
        assert_eq!(*metrics.calls_by_model.get("claude-opus").unwrap(), 1);

        // Record another call
        let call2 = ApiCall::new(
            Utc::now(),
            "worker-2",
            "claude-sonnet",
            500,
            250,
            0.02,
