            .filter(|e| matches!(e, LogWatcherEvent::ApiCallParsed { .. }))
            .count();
        assert_eq!(parsed2, 1, "Expected 1 new parsed call, got {} events: {:?}", parsed2, events2);

        // Poll again - no new content
        let events3 = watcher.poll();
        let parsed3 = events3
            .iter()
            .filter(|e| matches!(e, LogWatcherEvent::ApiCallParsed { .. }))
            .count();
        assert_eq!(parsed3, 0);
