        assert_eq!(app.selected_task_index, 5);

        // Press 'j' to move down again
        let key = KeyEvent::new(KeyCode::Char('j'), KeyModifiers::NONE);
        app.handle_key_event(key);
        assert_eq!(app.selected_task_index, 6);
    }

