    #[test]
    #[serial(file_watcher)]
    fn test_status_watcher_creates_directory() {
        let temp_dir = TempDir::new().unwrap();
        let status_dir = temp_dir.path().join("forge").join("status");

        assert!(!status_dir.exists());

