        std::thread::sleep(Duration::from_millis(100));
        while watcher.recv_timeout(Duration::from_millis(50)).is_some() {}

        assert!(
            watcher.get_worker(new_worker_id).is_some(),
            "Watcher should still track new workers after corruption"
        );
    }

